-- SR33 "C4" real ORC polar (Best Performance envelope). Generated by
-- vps/agent/knowledge/build_speed_guide.py from the ORC certificate.
-- Replaces synthetic placeholder polars. Idempotent.
DELETE FROM polars WHERE boat_id = 'sr33';
ON CONFLICT (boat_id, tws, twa) DO UPDATE
  SET target_stw = EXCLUDED.target_stw, target_vmg = EXCLUDED.target_vmg;
